import{_ as a,o as e,c as r,a2 as o}from"./chunks/framework.BQ1gajhD.js";const f=JSON.parse('{"title":"保和殿","description":"","frontmatter":{},"headers":[],"relativePath":"landmarks/forbidden-city/baohe-dian.md","filePath":"landmarks/forbidden-city/baohe-dian.md","lastUpdated":1784720050000}'),n={name:"landmarks/forbidden-city/baohe-dian.md"};function l(s,t,i,d,g,h){return e(),r("div",null,[...t[0]||(t[0]=[o('<h1 id="保和殿" tabindex="-1">保和殿 <a class="header-anchor" href="#保和殿" aria-label="Permalink to &quot;保和殿&quot;">​</a></h1><p><img src="https://images.unsplash.com/photo-1551101509-fd2fa880106e?w=1200&amp;q=80" alt="保和殿"></p><blockquote><p>殿试抡才，云龙镇阶。这里是帝国选才的最高考场，殿后那块250吨的巨石，是紫禁城最沉重的秘密。</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>保和殿是外朝三大殿的最后一座，位于中和殿之北，建成于明永乐十八年（1420年），初名&quot;谨身殿&quot;，嘉靖年间改名&quot;建极殿&quot;，清顺治二年（1645年）定名&quot;保和殿&quot;，与太和、中和合取《周易》&quot;保合太和&quot;之意。面阔九间，进深五间，重檐歇山顶，是三大殿中等级略低但仍极尽宏伟的一座。</p><p>保和殿在清代承担着两项重要功能：一是<strong>殿试考场</strong>——乾隆五十四年（1789年）起，科举最高级别的殿试固定于此举行，天子亲自主持，钦点状元；二是<strong>国宴场所</strong>——每年除夕和正月十五，皇帝在此宴请外藩王公及一二品大臣，是紫禁城中最隆重的宫廷宴会厅。</p><p>然而，保和殿最令人震撼的并非殿宇本身，而是殿后御路上那块举世无双的<strong>云龙阶石</strong>。</p><h2 id="建筑与景观" tabindex="-1">建筑与景观 <a class="header-anchor" href="#建筑与景观" aria-label="Permalink to &quot;建筑与景观&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">数据</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>面阔</strong></td><td style="text-align:left;">九间，49.65米</td></tr><tr><td style="text-align:left;"><strong>进深</strong></td><td style="text-align:left;">五间，24.97米</td></tr><tr><td style="text-align:left;"><strong>屋顶</strong></td><td style="text-align:left;">重檐歇山顶（等级仅次于太和殿的庑殿顶）</td></tr><tr><td style="text-align:left;"><strong>殿前月台</strong></td><td style="text-align:left;">三层须弥座台基，与太和殿、中和殿共用</td></tr><tr><td style="text-align:left;"><strong>云龙阶石</strong></td><td style="text-align:left;">长16.57米，宽3.07米，厚1.7米，重约250吨</td></tr><tr><td style="text-align:left;"><strong>殿试时间</strong></td><td style="text-align:left;">清代乾隆五十四年（1789年）起固定于此</td></tr></tbody></table><p>保和殿坐落于与太和殿、中和殿相连的三层汉白玉台基之上，三殿共用一座工字形大台基，是紫禁城建筑群的精华所在。殿身重檐歇山，黄琉璃瓦覆顶，檐角九只走兽，规制仅次于太和殿。</p><p>殿内曾设皇帝宝座，殿试时则撤去宝座，改摆考桌。试想：帝国最顶尖的贡士们伏案于天子脚下，殿外侍卫肃立，殿上皇帝巡阅——这是科举时代读书人一生的巅峰时刻。</p><p>**殿后大石雕&quot;云龙阶石&quot;**是故宫最大的石雕，也是中国古代石雕艺术的巅峰之作：整块汉白玉上雕刻九条蟠龙，腾跃于云海波涛之间，龙身矫健、云纹翻卷，雕工精细入微。这块巨石采自北京房山大石窝，距紫禁城约50公里，运输耗时近一个月——据载动用上万民夫，沿途打井泼水成冰，在冰道上拖行而至。</p><h2 id="历史故事" tabindex="-1">历史故事 <a class="header-anchor" href="#历史故事" aria-label="Permalink to &quot;历史故事&quot;">​</a></h2><h3 id="_250吨巨石如何运进城" tabindex="-1">250吨巨石如何运进城？ <a class="header-anchor" href="#_250吨巨石如何运进城" aria-label="Permalink to &quot;250吨巨石如何运进城？&quot;">​</a></h3><p>云龙阶石的运输本身就是一个工程奇迹。明弘治年间开采此石时，房山到京城没有公路可走如此庞然大物。工匠们选择在最寒冷的冬季动工：沿途每隔一里打一口井，将井水泼洒路面，冻成一条冰道，巨石置于特制的旱船之上，由上万民夫和数千骡马在冰面上缓缓拖曳。50公里的路程走了近28天，耗费白银11万两。当这块巨石终于安卧于保和殿后时，它已不仅是一块建材，而是举国之力的纪念碑。</p><h3 id="殿试-从贡士到状元的一日之隔" tabindex="-1">殿试：从贡士到状元的一日之隔 <a class="header-anchor" href="#殿试-从贡士到状元的一日之隔" aria-label="Permalink to &quot;殿试：从贡士到状元的一日之隔&quot;">​</a></h3><p>清代殿试每三年一科，于农历三月或四月在保和殿举行。贡士们黎明入宫，在殿内及廊下就座，一日之内完成策论一道。试卷由读卷大臣评阅后，皇帝亲定一甲三名（状元、榜眼、探花）及二甲、三甲名次。放榜之日，状元、榜眼、探花从太和殿传出，再由<strong>午门中门</strong>出宫——这是臣子一生中唯一一次可走御道的荣耀。多少寒窗苦读，就为保和殿内这一日的笔墨。</p><h2 id="必看亮点" tabindex="-1">必看亮点 <a class="header-anchor" href="#必看亮点" aria-label="Permalink to &quot;必看亮点&quot;">​</a></h2><ul><li><strong>云龙阶石</strong>：绕到保和殿背面，这块长逾16米、重250吨的整石雕刻是故宫必看的&quot;镇殿之宝&quot;，九条龙的雕工值得贴近细赏。</li><li><strong>三层台基全景</strong>：从保和殿后回望，三大殿的工字形大台基层层收分，是紫禁城中轴线最壮阔的建筑剖面。</li><li><strong>殿试的历史现场</strong>：站在殿前月台上，想象当年贡士伏案、天子巡阅的场景——这里走出了清代一百多位状元。</li><li><strong>除夕国宴的想象</strong>：殿内曾摆满御宴桌椅，外藩王公、蒙古贵族觥筹交错——保和殿曾是帝国怀柔四方的外交舞台。</li></ul><h2 id="参观贴士" tabindex="-1">参观贴士 <a class="header-anchor" href="#参观贴士" aria-label="Permalink to &quot;参观贴士&quot;">​</a></h2><ul><li><strong>先看殿后石雕</strong>：多数游客只看殿前，保和殿后的云龙阶石才是真正的精华。沿殿侧绕行至背面，别错过。</li><li><strong>拍照角度</strong>：从保和殿后的高处（乾清门方向回望）可以拍到三大殿台基的层叠全景。</li><li><strong>中轴线的转折点</strong>：保和殿后是一道陡降的台阶，走下台阶便从&quot;外朝&quot;进入&quot;内廷&quot;，空间尺度骤然收缩——这是故宫设计有意营造的&quot;由公入私&quot;的过渡。</li><li><strong>下午光线佳</strong>：保和殿朝南，下午阳光斜照殿后石雕时，云龙浮雕的立体感最强。</li></ul><hr><p><strong>📍 位置</strong>：外朝中轴线最北端，三大殿之末 <strong>⏱️ 建议游览</strong>：20-30分钟 <strong>🔗 上一站</strong>：<a href="/beijing-travel-guide/landmarks/forbidden-city/zhonghe-dian.html">中和殿</a><strong>🔗 下一站</strong>：<a href="/beijing-travel-guide/landmarks/forbidden-city/qianqing-gong.html">乾清宫</a>（经乾清门进入内廷） <strong>🔗 返回</strong>：<a href="/beijing-travel-guide/landmarks/forbidden-city/">故宫博物院概览</a></p>',23)])])}const c=a(n,[["render",l]]);export{f as __pageData,c as default};
